export default function HealthCardPage() {
  const { data: session } = useSession();
  const { data: profile, isLoading } = useQuery({ queryKey: ["profile"], queryFn: fetchProfile });

  const patientId = profile?.patientCode ?? session?.user?.patientCode ?? "—";
  const fullName  = profile ? `${profile.firstName} ${profile.lastName}` : session?.user?.name ?? "—";
  const dob       = profile?.dob ? new Date(profile.dob).toLocaleDateString("en-US", { month: "long", day: "numeric", year: "numeric" }) : "—";

  function handlePrint() {
    window.print();
  }

  function handleShare() {
    if (navigator.share) {
      navigator.share({ title: "NWDI Health Card", text: `Patient: ${fullName}\nID: ${patientId}` })
        .catch(() => {});
    } else {
      navigator.clipboard.writeText(`Patient: ${fullName}\nID: ${patientId}`);
      toast.success("Patient info copied to clipboard");
    }
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <div className="flex items-center gap-2 mb-1">
          <div className="flex h-8 w-8 items-center justify-center rounded-xl bg-primary/10 border border-primary/20">
            <CreditCard className="h-4 w-4 text-primary" />
          </div>
          <span className="text-xs font-semibold text-primary tracking-widest uppercase">Identity</span>
        </div>
        <h1 className="text-2xl font-bold text-foreground">Digital Health Card</h1>
        <p className="text-sm text-muted-foreground mt-0.5">Your digital patient identification card</p>
      </div>

      {/* Card */}
      <div className="flex justify-center">
        <div
          className="w-full max-w-sm rounded-3xl overflow-hidden shadow-2xl print:shadow-none"
          style={{ background: "var(--gradient-hero)" }}
        >
          {/* Card header */}
          <div className="px-6 pt-6 pb-4">
            <div className="flex items-center gap-3">
              <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-white/15 border border-white/20">
                <span className="text-white font-bold text-sm">NW</span>
              </div>
              <div>
                <p className="text-white font-bold text-sm leading-none">NWDI</p>
                <p className="text-white/50 text-[10px] tracking-widest uppercase mt-0.5">Patient Portal</p>
              </div>
              <div className="ml-auto">
                <span className="inline-flex items-center gap-1 text-[10px] font-semibold text-white/80 bg-white/10 border border-white/20 rounded-full px-2.5 py-1">
                  <span className="h-1.5 w-1.5 rounded-full bg-green-400 inline-block" />
                  Active
                </span>
              </div>
            </div>
          </div>

          {/* QR code area */}
          <div className="flex justify-center py-4 bg-white/5">
            {isLoading
              ? <div className="h-36 w-36 rounded-xl bg-white/10 animate-pulse" />
              : <QrPlaceholder value={patientId} />
            }
          </div>

          {/* Patient info */}
          <div className="px-6 py-5 space-y-3">
            {isLoading ? (
              <>
                <div className="h-5 w-48 rounded bg-white/10 animate-pulse" />
                <div className="h-3 w-32 rounded bg-white/10 animate-pulse" />
              </>
            ) : (
              <>
                <div>
                  <p className="text-white/50 text-[10px] uppercase tracking-widest">Patient Name</p>
                  <p className="text-white font-bold text-lg leading-tight mt-0.5">{fullName}</p>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <p className="text-white/50 text-[10px] uppercase tracking-widest">Patient ID</p>
                    <p className="text-white font-mono text-sm font-semibold mt-0.5">{patientId}</p>
                  </div>
                  <div>
                    <p className="text-white/50 text-[10px] uppercase tracking-widest">Date of Birth</p>
                    <p className="text-white text-xs mt-0.5">{dob}</p>
                  </div>
                </div>
              </>
            )}
          </div>

          {/* Card footer */}
          <div className="px-6 py-3 border-t border-white/10 flex items-center justify-between">
            <div className="flex items-center gap-1.5">
              <BadgeCheck className="h-3.5 w-3.5 text-green-400" />
              <span className="text-[10px] text-white/60">NWDI Verified Patient</span>
            </div>
            <QrCode className="h-4 w-4 text-white/30" />
          </div>
        </div>
      </div>

      {/* Info */}
      <div className="rounded-2xl border border-border bg-card p-4">
        <p className="text-xs text-muted-foreground leading-relaxed">
          Present this digital card at any NWDI branch. The QR code contains your Patient ID and can be scanned by
          our staff to quickly retrieve your records. This card is linked to your registered account.
        </p>
      </div>

      {/* Actions */}
      <div className="flex gap-3">
        <button
          onClick={handlePrint}
          className="flex-1 flex items-center justify-center gap-2 h-11 rounded-xl border border-border bg-card text-sm font-semibold text-foreground hover:bg-muted transition-colors"
        >
          <Download className="h-4 w-4" /> Save / Print
        </button>
        <button
          onClick={handleShare}
          className="flex-1 flex items-center justify-center gap-2 h-11 rounded-xl text-sm font-semibold text-white hover:opacity-90 transition-opacity"
          style={{ background: "var(--gradient-primary)" }}
        >
          <Share2 className="h-4 w-4" /> Share Card
        </button>
      </div>
    </div>
  );
}
